rewritten_response:
def fibonacci(n):
    if not isinstance(n, int) or n < 1:
        raise ValueError('Input should be a positive integer')
    elif n == 1:
        return 0
    elif n == 2:
        return 1
    else:
        fib_sequence = [0, 1]
        while len(fib_sequence) < n:
            fib_sequence.append(fib_sequence[-1] + fib_sequence[-2])
        return fib_sequence[-1]
